  1→/**
  2→ * Email Delivery Service for ZeroToShip
  3→ *
  4→ * Sends daily brief emails to subscribers via Resend.
  5→ * Handles subscriber tiers and tracks delivery status.
  6→ */
  7→
  8→import type { IdeaBrief } from '../generation/brief-generator';
  9→import { config as envConfig } from '../config/env';
 10→import {
 11→  buildDailyEmail,
 12→  type SubscriberTier,
 13→  type EmailContent,
 14→  type EmailBuilderConfig,
 15→} from './email-builder';
 16→import { DeliveryError } from '../lib/errors';
 17→
 18→/** Send one email at a time — Resend free tier allows only 2 req/s and concurrent
 19→ *  sends + retries easily blow past that. Sequential is the only safe approach. */
 20→const DEFAULT_EMAIL_CONCURRENCY = 1;
 21→
 22→/** Delay between each email (ms) — 1 second keeps us well under the 2 req/s limit
 23→ *  even when a retry fires within the same window. */
 24→const DEFAULT_EMAIL_DELAY_MS = 1_000;
 25→
 26→/**
 27→ * Subscriber information
 28→ */
 29→export interface Subscriber {
 30→  id: string;
 31→  email: string;
 32→  tier: SubscriberTier;
 33→  unsubscribeToken?: string;
 34→}
 35→
 36→/**
 37→ * Delivery status for tracking
 38→ */
 39→export interface DeliveryStatus {
 40→  subscriberId: string;
 41→  email: string;
 42→  messageId: string | null;
 43→  status: 'sent' | 'failed' | 'bounced' | 'pending';
 44→  error?: string;
 45→  sentAt: Date;
 46→}
 47→
 48→/**
 49→ * Batch delivery result
 50→ */
 51→export interface BatchDeliveryResult {
 52→  total: number;
 53→  sent: number;
 54→  failed: number;
 55→  deliveries: DeliveryStatus[];
 56→}
 57→
 58→/**
 59→ * Email service configuration
 60→ */
 61→export interface EmailServiceConfig {
 62→  resendApiKey?: string;
 63→  fromEmail?: string;
 64→  fromName?: string;
 65→  replyTo?: string;
 66→  builderConfig?: EmailBuilderConfig;
 67→}
 68→
 69→const DEFAULT_CONFIG: Required<Omit<EmailServiceConfig, 'builderConfig'>> & {
 70→  builderConfig: EmailBuilderConfig;
 71→} = {
 72→  resendApiKey: '',
 73→  fromEmail: envConfig.RESEND_FROM_EMAIL || 'briefs@zerotoship.dev',
 74→  fromName: envConfig.RESEND_FROM_NAME || 'ZeroToShip',
 75→  replyTo: 'hello@zerotoship.dev',
 76→  builderConfig: {},
 77→};
 78→
 79→/**
 80→ * Resend API response types
 81→ */
 82→interface ResendSuccessResponse {
 83→  id: string;
 84→}
 85→
 86→interface ResendErrorResponse {
 87→  statusCode: number;
 88→  message: string;
 89→  name: string;
 90→}
 91→
 92→/**
 93→ * Send a single email via Resend API
 94→ */
 95→async function sendViaResend(
 96→  apiKey: string,
 97→  from: string,
 98→  to: string,
 99→  replyTo: string,
100→  content: EmailContent
101→): Promise<{ success: boolean; messageId?: string; error?: string }> {
102→  const sleep = (ms: number) => new Promise((resolve) => setTimeout(resolve, ms));
103→  const isRetryableStatus = (status: number) => status === 429 || status >= 500;
104→
105→  const MAX_ATTEMPTS = 3;
106→  const BACKOFF_BASE_MS = envConfig.isTest ? 0 : 1_000;
107→  const jitterMs = () => (envConfig.isTest ? 0 : Math.floor(Math.random() * 300));
108→
109→  for (let attempt = 1; attempt <= MAX_ATTEMPTS; attempt++) {
110→    try {
111→      const response = await fetch('https://api.resend.com/emails', {
112→        method: 'POST',
113→        headers: {
114→          'Authorization': `Bearer ${apiKey}`,
115→          'Content-Type': 'application/json',
116→        },
117→        body: JSON.stringify({
118→          from,
119→          to: [to],
120→          reply_to: replyTo,
121→          subject: content.subject,
122→          html: content.html,
123→          text: content.text,
124→        }),
125→      });
126→
127→      if (!response.ok) {
128→        let parsed: Partial<ResendErrorResponse> | null = null;
129→        let raw = '';
130→        try {
131→          if (typeof (response as unknown as { json?: unknown }).json === 'function') {
132→            parsed = (await (response as unknown as { json: () => Promise<unknown> }).json()) as Partial<ResendErrorResponse>;
133→          } else if (typeof (response as unknown as { text?: unknown }).text === 'function') {
134→            raw = await (response as unknown as { text: () => Promise<string> }).text();
135→          }
136→        } catch {
137→          // ignore parse errors; we'll fall back to an unknown message
138→        }
139→
140→        const message = parsed?.message || raw || 'Unknown Resend API error';
141→        const err = new DeliveryError(
142→          `Resend API error (${response.status}): ${message}`,
143→          { context: { to, statusCode: response.status, attempt } }
144→        );
145→
146→        if (attempt < MAX_ATTEMPTS && isRetryableStatus(response.status)) {
147→          const backoffMs = BACKOFF_BASE_MS * (2 ** (attempt - 1)) + jitterMs();
148→          await sleep(backoffMs);
149→          continue;
150→        }
151→
152→        return { success: false, error: err.message };
153→      }
154→
155→      const data = (await response.json()) as ResendSuccessResponse;
156→      return { success: true, messageId: data.id };
157→    } catch (error) {
158→      const err = new DeliveryError(
159→        error instanceof Error ? error.message : 'Unknown error',
160→        { context: { to, attempt }, cause: error instanceof Error ? error : undefined }
161→      );
162→
163→      if (attempt < MAX_ATTEMPTS) {
164→        const backoffMs = BACKOFF_BASE_MS * (2 ** (attempt - 1)) + jitterMs();
165→        await sleep(backoffMs);
166→        continue;
167→      }
168→
169→      return { success: false, error: err.message };
170→    }
171→  }
172→
173→  return { success: false, error: 'Email send failed after retries' };
174→}
175→
176→/**
177→ * Build personalized unsubscribe URL for a subscriber
178→ */
179→function buildUnsubscribeUrl(baseUrl: string, subscriber: Subscriber): string {
180→  const token = subscriber.unsubscribeToken || subscriber.id;
181→  return `${baseUrl}/unsubscribe?token=${encodeURIComponent(token)}`;
182→}
183→
184→/**
185→ * Send daily brief email to a single subscriber
186→ */
187→export async function sendDailyBrief(
188→  subscriber: Subscriber,
189→  briefs: IdeaBrief[],
190→  config: EmailServiceConfig = {}
191→): Promise<DeliveryStatus> {
192→  const opts = { ...DEFAULT_CONFIG, ...config };
193→  const apiKey = opts.resendApiKey || envConfig.RESEND_API_KEY;
194→
195→  const status: DeliveryStatus = {
196→    subscriberId: subscriber.id,
197→    email: subscriber.email,
198→    messageId: null,
199→    status: 'pending',
200→    sentAt: new Date(),
201→  };
202→
203→  // Validate API key
204→  if (!apiKey) {
205→    status.status = 'failed';
206→    status.error = 'No Resend API key configured';
207→    return status;
208→  }
209→
210→  // Build personalized email content
211→  const builderConfig: EmailBuilderConfig = {
212→    ...opts.builderConfig,
213→    unsubscribeUrl: buildUnsubscribeUrl(
214→      opts.builderConfig?.baseUrl || 'https://zerotoship.dev',
215→      subscriber
216→    ),
217→  };
218→
219→  const emailContent = buildDailyEmail(briefs, subscriber.tier, builderConfig);
220→
221→  // Send via Resend
222→  const from = `${opts.fromName} <${opts.fromEmail}>`;
223→  const result = await sendViaResend(
224→    apiKey,
225→    from,
226→    subscriber.email,
227→    opts.replyTo,
228→    emailContent
229→  );
230→
231→  if (result.success) {
232→    status.status = 'sent';
233→    status.messageId = result.messageId || null;
234→  } else {
235→    status.status = 'failed';
236→    status.error = result.error;
237→  }
238→
239→  return status;
240→}
241→
242→/**
243→ * Send daily briefs to multiple subscribers
244→ */
245→export async function sendDailyBriefsBatch(
246→  subscribers: Subscriber[],
247→  briefs: IdeaBrief[],
248→  config: EmailServiceConfig = {},
249→  options: {
250→    concurrency?: number;
251→    delayMs?: number;
252→    onProgress?: (completed: number, total: number) => void;
253→  } = {}
254→): Promise<BatchDeliveryResult> {
255→  const { concurrency = DEFAULT_EMAIL_CONCURRENCY, delayMs = DEFAULT_EMAIL_DELAY_MS, onProgress } = options;
256→
257→  const result: BatchDeliveryResult = {
258→    total: subscribers.length,
259→    sent: 0,
260→    failed: 0,
261→    deliveries: [],
262→  };
263→
264→  if (subscribers.length === 0) {
265→    return result;
266→  }
267→
268→  // Process in batches
269→  for (let i = 0; i < subscribers.length; i += concurrency) {
270→    const batch = subscribers.slice(i, i + concurrency);
271→
272→    const batchPromises = batch.map(subscriber =>
273→      sendDailyBrief(subscriber, briefs, config)
274→    );
275→
276→    const batchResults = await Promise.all(batchPromises);
277→
278→    for (const delivery of batchResults) {
279→      result.deliveries.push(delivery);
280→      if (delivery.status === 'sent') {
281→        result.sent++;
282→      } else {
283→        result.failed++;
284→      }
285→    }
286→
287→    // Progress callback
288→    if (onProgress) {
289→      const completed = Math.min(i + concurrency, subscribers.length);
290→      onProgress(completed, subscribers.length);
291→    }
292→
293→    // Rate limiting delay between batches
294→    if (i + concurrency < subscribers.length && delayMs > 0) {
295→      await new Promise(resolve => setTimeout(resolve, delayMs));
296→    }
297→  }
298→
299→  return result;
300→}
301→
302→/**
303→ * Preview email without sending (for testing)
304→ */
305→export function previewDailyBrief(
306→  tier: SubscriberTier,
307→  briefs: IdeaBrief[],
308→  config: EmailBuilderConfig = {}
309→): EmailContent {
310→  return buildDailyEmail(briefs, tier, config);
311→}
312→
313→/**
314→ * Validate email address format
315→ */
316→export function isValidEmail(email: string): boolean {
317→  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
318→  return emailRegex.test(email);
319→}
320→
321→/**
322→ * Filter failed deliveries for retry
323→ */
324→export function getFailedDeliveries(result: BatchDeliveryResult): DeliveryStatus[] {
325→  return result.deliveries.filter(d => d.status === 'failed');
326→}
327→
328→/**
329→ * Get delivery statistics
330→ */
331→export function getDeliveryStats(result: BatchDeliveryResult): {
332→  successRate: number;
333→  failureRate: number;
334→  averagePerSecond: number;
335→} {
336→  const successRate = result.total > 0 ? (result.sent / result.total) * 100 : 0;
337→  const failureRate = result.total > 0 ? (result.failed / result.total) * 100 : 0;
338→
339→  // Estimate delivery rate (concurrency * 1000 / delayMs)
340→  const ESTIMATED_EMAILS_PER_SECOND = DEFAULT_EMAIL_CONCURRENCY * (1000 / DEFAULT_EMAIL_DELAY_MS);
341→  const averagePerSecond = result.total > 0 ? ESTIMATED_EMAILS_PER_SECOND : 0;
342→
343→  return {
344→    successRate,
345→    failureRate,
346→    averagePerSecond,
347→  };
348→}
