350→/**
351→ * Create a test subscriber for development
352→ */
353→export function createTestSubscriber(
354→  email: string,
355→  tier: SubscriberTier = 'free'
356→): Subscriber {
357→  return {
358→    id: `test_${Date.now()}`,
359→    email,
360→    tier,
361→    unsubscribeToken: `unsub_${Date.now()}`,
362→  };
363→}
