  1→/**
  2→ * Email Pro for ZeroToShip
  3→ *
  4→ * Generates HTML emails from daily briefs for different subscriber tiers.
  5→ * Strategy: emails are teasers that drive users to the website for full briefs.
  6→ */
  7→
  8→import type { IdeaBrief } from '../generation/brief-generator';
  9→import logger from '../lib/logger';
 10→
 11→export type SubscriberTier = 'free' | 'pro';
 12→
 13→export const TIER_LIMITS: Record<SubscriberTier, number> = {
 14→  free: 3,
 15→  pro: 10,
 16→};
 17→
 18→const MAX_EMAIL_IDEAS = 10;
 19→const TAGLINE_TRUNCATE_LENGTH = 80;
 20→
 21→export interface EmailContent {
 22→  subject: string;
 23→  html: string;
 24→  text: string;
 25→}
 26→
 27→export interface EmailBuilderConfig {
 28→  baseUrl?: string;
 29→  unsubscribeUrl?: string;
 30→  upgradeUrl?: string;
 31→}
 32→
 33→const DEFAULT_CONFIG: Required<EmailBuilderConfig> = {
 34→  baseUrl: 'https://zerotoship.dev',
 35→  unsubscribeUrl: 'https://zerotoship.dev/unsubscribe',
 36→  upgradeUrl: 'https://zerotoship.dev/pricing',
 37→};
 38→
 39→const FONT_STACK = "'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif";
 40→
 41→function escapeHtml(text: string): string {
 42→  const htmlEscapes: Record<string, string> = {
 43→    '&': '&amp;',
 44→    '<': '&lt;',
 45→    '>': '&gt;',
 46→    '"': '&quot;',
 47→    "'": '&#39;',
 48→  };
 49→  return text.replace(/[&<>"']/g, char => htmlEscapes[char]);
 50→}
 51→
 52→function formatScore(score: number | string): string {
 53→  return Number(score).toFixed(1);
 54→}
 55→
 56→function firstSentence(text: string): string {
 57→  const match = text.match(/^[^.!?]+[.!?]/);
 58→  return match ? match[0].trim() : text.slice(0, 150);
 59→}
 60→
 61→function getEffortBadgeStyle(effort: string): { bg: string; text: string } {
 62→  const lower = effort.toLowerCase();
 63→  if (lower === 'weekend') return { bg: '#ecfdf5', text: '#059669' };
 64→  if (lower === 'week') return { bg: '#fef3c7', text: '#d97706' };
 65→  return { bg: '#fee2e2', text: '#dc2626' };
 66→}
 67→
 68→function formatEffortLabel(effort: string): string {
 69→  const lower = effort.toLowerCase();
 70→  if (lower === 'weekend') return 'Weekend';
 71→  if (lower === 'week') return '1 Week';
 72→  if (lower === 'month') return '1 Month';
 73→  if (lower === 'quarter') return 'Quarter+';
 74→  return effort;
 75→}
 76→
 77→function generateSubjectLine(topIdea: IdeaBrief, ideaCount: number): string {
 78→  const name = topIdea.name.trim();
 79→  const effort = formatEffortLabel(topIdea.effortEstimate).toLowerCase();
 80→
 81→  // Specific > generic. Lead with the product name or effort level so
 82→  // the subject conveys value at a glance. Avoid revenue claims and questions.
 83→  const templates = [
 84→    `Today's #1: ${name} (${effort} build)`,
 85→    `${name} — ${effort} build, ${formatScore(topIdea.priorityScore)}/100`,
 86→    `${ideaCount} problems scored — ${name} leads`,
 87→    `${name} tops today's ${ideaCount} problems`,
 88→  ];
 89→
 90→  // Deterministic daily selection based on date
 91→  const dateHash = new Date().toISOString().slice(0, 10).split('').reduce((a, c) => a + c.charCodeAt(0), 0);
 92→  const subject = templates[dateHash % templates.length];
 93→
 94→  // Most inboxes truncate around ~50 chars. Target a tighter ceiling.
 95→  return subject.length > 52 ? subject.slice(0, 49) + '...' : subject;
 96→}
 97→
 98→function generatePreviewText(topIdea: IdeaBrief, ideaCount: number): string {
 99→  return `${ideaCount} problems scored today. #1 is a ${formatEffortLabel(topIdea.effortEstimate).toLowerCase()} build.`;
100→}
101→
102→function buildPreheader(text: string): string {
103→  const spacer = '&#847;&zwnj;&nbsp;'.repeat(15);
104→  return `<span style="display:none;font-size:0;line-height:0;max-height:0;max-width:0;mso-hide:all;overflow:hidden;">${escapeHtml(text)}${spacer}</span>`;
105→}
106→
107→function buildHeader(dateStr: string): string {
108→  return `
109→    <table width="100%" cellpadding="0" cellspacing="0" role="presentation" style="border-bottom: 2px solid #6366f1;">
110→      <tr>
111→        <td style="padding: 16px 24px; font-family: ${FONT_STACK};">
112→          <table width="100%" cellpadding="0" cellspacing="0" role="presentation">
113→            <tr>
114→              <td style="font-size: 20px; font-weight: 700; color: #111827;">ZeroToShip</td>
115→              <td style="text-align: right; font-size: 13px; color: #9ca3af;">${escapeHtml(dateStr)}</td>
116→            </tr>
117→          </table>
118→        </td>
119→      </tr>
120→    </table>`;
121→}
122→
123→function buildStatBar(ideaCount: number, topScore: string): string {
124→  return `
125→    <table width="100%" cellpadding="0" cellspacing="0" role="presentation" style="background-color: #f9fafb;">
126→      <tr>
127→        <td style="padding: 12px 24px; font-family: ${FONT_STACK}; font-size: 13px; color: #6b7280; text-align: center;">
128→          <strong style="color: #111827;">${ideaCount}</strong> problems found &nbsp;&middot;&nbsp;
129→          <strong style="color: #111827;">4</strong> communities scraped &nbsp;&middot;&nbsp;
130→          Top score: <strong style="color: #6366f1;">${topScore}</strong>
131→        </td>
132→      </tr>
133→    </table>`;
134→}
135→
136→function buildScoreChips(brief: IdeaBrief): string {
137→  const effortLabel = formatEffortLabel(brief.effortEstimate);
138→  return `
139→          <table width="100%" cellpadding="0" cellspacing="0" role="presentation" style="margin: 0 0 20px 0;">
140→            <tr>
141→              <td width="48%" style="background: #ffffff; padding: 10px 12px; border-radius: 8px; border: 1px solid #e5e7eb; text-align: center;">
142→                <div style="font-size: 10px; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px;">Priority</div>
143→                <div style="font-size: 18px; font-weight: 700; color: #6366f1; margin-top: 2px;">${formatScore(brief.priorityScore)}</div>
144→              </td>
145→              <td width="4%"></td>
146→              <td width="48%" style="background: #ffffff; padding: 10px 12px; border-radius: 8px; border: 1px solid #e5e7eb; text-align: center;">
147→                <div style="font-size: 10px; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px;">Build time</div>
148→                <div style="font-size: 18px; font-weight: 700; color: #111827; margin-top: 2px;">${escapeHtml(effortLabel)}</div>
149→              </td>
150→            </tr>
151→          </table>`;
152→}
153→
154→function buildSectionBlock(label: string, content: string): string {
155→  return `
156→          <div style="margin-bottom: 16px;">
157→            <div style="font-size: 11px; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px; margin-bottom: 6px;">${label}</div>
158→            <p style="margin: 0; font-size: 15px; color: #374151; line-height: 1.6;">${content}</p>
159→          </div>`;
160→}
161→
162→function buildHeroSection(brief: IdeaBrief, tier: SubscriberTier, config: Required<EmailBuilderConfig>): string {
163→  const ideaPath = `/idea/${brief.id || ''}`;
164→  // Email links are often opened in a logged-out browser session. For free users,
165→  // route through login with `next` so they land on a fully-unlocked brief after auth.
166→  const ideaUrl = tier === 'free'
167→    ? `${config.baseUrl}/login?next=${encodeURIComponent(ideaPath)}`
168→    : `${config.baseUrl}${ideaPath}`;
169→
170→  const headerHtml = `
171→          <span style="display: inline-block; background-color: #6366f1; color: #ffffff; padding: 4px 12px; border-radius: 16px; font-size: 11px; font-weight: 600; text-transform: uppercase; letter-spacing: 0.5px;">Today's #1 Problem</span>
172→          <h2 style="margin: 12px 0 4px 0; font-size: 24px; font-weight: 700; color: #111827; line-height: 1.3;">${escapeHtml(brief.name)}</h2>
173→          <p style="margin: 0 0 16px 0; font-size: 16px; color: #6b7280; font-style: italic;">${escapeHtml(brief.tagline)}</p>`;
174→
175→  let bodyHtml: string;
176→
177→  if (tier === 'pro') {
178→    // Pro: full brief sections in the email
179→    const features = brief.keyFeatures.slice(0, 5);
180→    const featureListHtml = features.length > 0
181→      ? `
182→          <div style="margin-bottom: 16px;">
183→            <div style="font-size: 11px; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px; margin-bottom: 6px;">Key Features</div>
184→            ${features.map(f => `<div style="padding: 4px 0 4px 16px; font-size: 15px; color: #374151; line-height: 1.5; position: relative;"><span style="color: #059669; position: absolute; left: 0;">&#10003;</span> ${escapeHtml(f)}</div>`).join('\n            ')}
185→          </div>`
186→      : '';
187→
188→    const gtmHtml = brief.goToMarket
189→      ? buildSectionBlock('Go-to-Market', `${escapeHtml(brief.goToMarket.launchStrategy)}`)
190→      : '';
191→
192→    bodyHtml = `
193→          ${buildSectionBlock('The Problem', escapeHtml(brief.problemStatement))}
194→          ${buildSectionBlock('Target Audience', escapeHtml(brief.targetAudience))}
195→          ${buildSectionBlock('Proposed Solution', escapeHtml(brief.proposedSolution))}
196→          ${featureListHtml}
197→          ${gtmHtml}`;
198→  } else {
199→    // Free: teaser hook only
200→    const hook = firstSentence(brief.problemStatement);
201→    const featureTeaser = brief.keyFeatures.length > 0
202→      ? ` The brief covers ${escapeHtml(brief.keyFeatures[0].toLowerCase())}${brief.keyFeatures.length > 1 ? ` and ${brief.keyFeatures.length - 1} more technical approaches` : ''}.`
203→      : '';
204→
205→    bodyHtml = `
206→          <p style="margin: 0 0 20px 0; font-size: 16px; color: #374151; line-height: 1.6;">${escapeHtml(hook)}${featureTeaser}</p>`;
207→  }
208→
209→  const ctaLabel = tier === 'pro' ? 'View full spec on dashboard' : 'Read the full spec';
210→
211→  return `
212→    <table width="100%" cellpadding="0" cellspacing="0" role="presentation">
213→      <tr>
214→        <td style="padding: 24px; font-family: ${FONT_STACK};">
215→          ${headerHtml}
216→          ${buildScoreChips(brief)}
217→          ${bodyHtml}
218→          <table cellpadding="0" cellspacing="0" role="presentation">
219→            <tr>
220→              <td style="background-color: #6366f1; border-radius: 8px;">
221→                <a href="${escapeHtml(ideaUrl)}" style="display: inline-block; padding: 14px 28px; color: #ffffff; font-family: ${FONT_STACK}; font-size: 16px; font-weight: 600; text-decoration: none; border-radius: 8px;">${ctaLabel} &#8594;</a>
222→              </td>
223→            </tr>
224→          </table>
225→        </td>
226→      </tr>
227→    </table>`;
228→}
229→
230→function buildInlineUpgradeBanner(
231→  briefs: IdeaBrief[],
232→  config: Required<EmailBuilderConfig>
233→): string {
234→  const ideaCount = Math.min(briefs.length, MAX_EMAIL_IDEAS);
235→
236→  // Rotate copy based on day
237→  const dateHash = new Date().toISOString().slice(0, 10).split('').reduce((a, c) => a + c.charCodeAt(0), 0);
238→  const variants = [
239→    `You're seeing 1 of today's ${ideaCount} problems. Pro members get full specs for every one.`,
240→    `Today's lineup has ${ideaCount - 1} more problems just like this one.`,
241→    briefs.length >= 3
