 13→/** Escape HTML special characters */
 14→function escapeHtml(text: string): string {
 15→  const htmlEscapes: Record<string, string> = {
 16→    '&': '&amp;',
 17→    '<': '&lt;',
 18→    '>': '&gt;',
 19→    '"': '&quot;',
 20→    "'": '&#39;',
 21→  };
 22→  return text.replace(/[&<>"']/g, (char) => htmlEscapes[char]);
 23→}
 24→
 25→/** Truncate text to a maximum length with ellipsis */
 26→function truncate(text: string, maxLength: number): string {
 27→  if (text.length <= maxLength) return text;
 28→  return text.slice(0, maxLength).trimEnd() + '...';
 29→}
