  1→/**
  2→ * Deliver Phase Runner
  3→ *
  4→ * Sends daily brief emails to subscribers.
  5→ */
  6→
  7→import {
  8→  sendDailyBriefsBatch,
  9→  type Subscriber,
 10→} from '../../delivery/email';
 11→import { processOnboardingDrip } from '../../delivery/onboarding';
 12→import type { IdeaBrief } from '../../generation/brief-generator';
 13→import { createPhaseLogger } from '../utils/logger';
 14→import { DeliveryError, wrapError } from '../../lib/errors';
 15→import type {
 16→  PhaseResult,
 17→  DeliverPhaseOutput,
 18→  PipelineConfig,
 19→} from '../types';
 20→import { db, users, subscriptions, userPreferences, emailLogs } from '../../api/db/client';
 21→import { eq } from 'drizzle-orm';
 22→
 23→/**
 24→ * Get active subscribers from database
 25→ */
 26→async function getActiveSubscribers(): Promise<Subscriber[]> {
 27→  const rows = await db
 28→    .select({
 29→      id: users.id,
 30→      email: users.email,
 31→      tier: subscriptions.plan,
 32→      emailFrequency: userPreferences.emailFrequency,
 33→    })
 34→    .from(users)
 35→    .innerJoin(subscriptions, eq(subscriptions.userId, users.id))
 36→    .leftJoin(userPreferences, eq(userPreferences.userId, users.id))
 37→    .where(eq(subscriptions.status, 'active'));
 38→
 39→  return rows
 40→    .filter((row) => row.emailFrequency !== 'never')
 41→    .map((row) => ({
 42→      id: row.id,
 43→      email: row.email,
 44→      tier: row.tier as Subscriber['tier'],
 45→    }));
 46→}
 47→
 48→/**
 49→ * Run the deliver phase
 50→ */
 51→export async function runDeliverPhase(
 52→  runId: string,
 53→  config: PipelineConfig,
 54→  briefs: IdeaBrief[]
 55→): Promise<PhaseResult<DeliverPhaseOutput>> {
 56→  const logger = createPhaseLogger(runId, 'deliver');
 57→  const startTime = Date.now();
 58→
 59→  logger.info(
 60→    { briefCount: briefs.length, dryRun: config.dryRun },
 61→    'Starting deliver phase'
 62→  );
 63→
 64→  try {
 65→    if (config.dryRun) {
 66→      logger.info('Dry run mode - skipping actual email delivery');
 67→
 68→      // In dry run, just log what would be sent
 69→      const subscribers = await getActiveSubscribers();
 70→
 71→      return {
 72→        success: true,
 73→        data: {
 74→          subscriberCount: subscribers.length,
 75→          sent: 0,
 76→          failed: 0,
 77→          dryRun: true,
 78→        },
 79→        duration: Date.now() - startTime,
 80→        phase: 'deliver',
 81→        timestamp: new Date(),
 82→      };
 83→    }
 84→
 85→    // Get subscribers
 86→    const subscribers = await getActiveSubscribers();
 87→
 88→    if (subscribers.length === 0) {
 89→      logger.warn('No active subscribers found');
 90→      return {
 91→        success: true, // Not a failure, just nothing to do
 92→        data: {
 93→          subscriberCount: 0,
 94→          sent: 0,
 95→          failed: 0,
 96→          dryRun: false,
 97→        },
 98→        duration: Date.now() - startTime,
 99→        phase: 'deliver',
100→        timestamp: new Date(),
101→      };
102→    }
103→
104→    // Send emails
105→    const result = await sendDailyBriefsBatch(
106→      subscribers,
107→      briefs,
108→      {}, // Use default config
109→      {
110→        onProgress: (completed, total) => {
111→          logger.debug({ completed, total }, 'Delivery progress');
112→        },
113→      }
114→    );
115→
116→    // Persist delivery statuses to email_logs
117→    try {
118→      const emailLogRows = result.deliveries
119→        .filter((d) => d.status === 'sent' || d.status === 'failed')
120→        .map((delivery) => ({
121→          runId,
122→          userId: delivery.subscriberId,
123→          recipientEmail: delivery.email,
124→          subject: `Your Daily Startup Ideas — ${new Date().toLocaleDateString()}`,
125→          messageId: delivery.messageId,
126→          status: delivery.status as string,
127→          error: delivery.error || null,
128→          sentAt: delivery.sentAt,
129→        }));
130→
131→      if (emailLogRows.length > 0) {
132→        await db.insert(emailLogs).values(emailLogRows);
133→      }
134→    } catch (logError) {
135→      logger.warn(
136→        { error: logError instanceof Error ? logError.message : String(logError) },
137→        'Failed to persist email delivery logs (non-fatal)'
138→      );
139→    }
140→
141→    const duration = Date.now() - startTime;
142→
143→    // Process onboarding drip emails after daily digest
144→    try {
145→      const dripResult = await processOnboardingDrip();
146→      logger.info(
147→        {
148→          onboardingSent: dripResult.sent,
149→          onboardingSkipped: dripResult.skipped,
150→          onboardingFailed: dripResult.failed,
151→        },
152→        'Onboarding drip processing complete'
153→      );
154→    } catch (dripError) {
155→      // Onboarding drip failures should not fail the deliver phase
156→      logger.warn(
157→        { error: dripError instanceof Error ? dripError.message : String(dripError) },
158→        'Onboarding drip processing failed (non-fatal)'
159→      );
160→    }
161→
162→    logger.info(
163→      {
164→        subscriberCount: subscribers.length,
165→        sent: result.sent,
166→        failed: result.failed,
167→        duration,
168→      },
169→      'Deliver phase complete'
170→    );
171→
172→    return {
173→      success: result.failed === 0 || result.sent > 0,
174→      data: {
175→        subscriberCount: subscribers.length,
176→        sent: result.sent,
177→        failed: result.failed,
178→        dryRun: false,
179→      },
180→      duration,
181→      phase: 'deliver',
182→      timestamp: new Date(),
183→    };
184→  } catch (error) {
185→    const duration = Date.now() - startTime;
186→    const deliveryError = wrapError(error, DeliveryError);
187→    const errorMessage = deliveryError.message;
188→
189→    logger.error({ error: errorMessage, severity: deliveryError.severity }, 'Deliver phase failed');
190→
191→    return {
192→      success: false,
193→      data: null,
194→      error: errorMessage,
195→      severity: deliveryError.severity,
196→      duration,
197→      phase: 'deliver',
198→      timestamp: new Date(),
199→    };
200→  }
201→}
