 1→/**
 2→ * Resend Webhook Routes
 3→ *
 4→ * Handles webhook events from Resend for email delivery tracking.
 5→ * Uses Svix for signature verification.
 6→ */
 7→
 8→import { FastifyPluginAsync, FastifyRequest } from 'fastify';
 9→import { Webhook } from 'svix';
10→import { config } from '../../config/env';
11→import { handleResendWebhookEvent, type ResendWebhookEvent } from '../services/resendWebhook';
12→
13→export const resendWebhookRoutes: FastifyPluginAsync = async (fastify) => {
14→  // Register raw body parser for webhook signature verification
15→  fastify.addContentTypeParser(
16→    'application/json',
17→    { parseAs: 'buffer' },
18→    (_req, body, done) => {
19→      done(null, body);
20→    }
21→  );
22→
23→  fastify.post(
24→    '/',
25→    async (request: FastifyRequest<{ Body: Buffer }>, reply) => {
26→      const svixId = request.headers['svix-id'] as string;
27→      const svixTimestamp = request.headers['svix-timestamp'] as string;
28→      const svixSignature = request.headers['svix-signature'] as string;
29→
30→      if (!svixId || !svixTimestamp || !svixSignature) {
31→        return reply.status(400).send({
32→          code: 'MISSING_SIGNATURE',
33→          message: 'Missing webhook signature headers',
34→        });
35→      }
36→
37→      const secret = config.RESEND_WEBHOOK_SECRET;
38→      if (!secret) {
39→        request.log.error('RESEND_WEBHOOK_SECRET not configured');
40→        return reply.status(500).send({
41→          code: 'CONFIG_ERROR',
42→          message: 'Webhook secret not configured',
43→        });
44→      }
45→
46→      try {
47→        const wh = new Webhook(secret);
48→        const payload = wh.verify(request.body.toString(), {
49→          'svix-id': svixId,
50→          'svix-timestamp': svixTimestamp,
51→          'svix-signature': svixSignature,
52→        }) as ResendWebhookEvent;
53→
54→        await handleResendWebhookEvent(payload);
55→
56→        return reply.send({ received: true });
57→      } catch (error) {
58→        if (error instanceof Error && (error.message.includes('signature') || error.message.includes('verification'))) {
59→          return reply.status(400).send({
60→            code: 'INVALID_SIGNATURE',
61→            message: 'Invalid webhook signature',
62→          });
63→        }
64→
65→        request.log.error({ error }, 'Webhook processing failed');
66→        return reply.status(400).send({
67→          code: 'WEBHOOK_ERROR',
68→          message: 'Webhook processing failed',
69→        });
70→      }
71→    }
72→  );
73→};
