238→  const variants = [
239→    `You're seeing 1 of today's ${ideaCount} problems. Pro members get full specs for every one.`,
240→    `Today's lineup has ${ideaCount - 1} more problems just like this one.`,
241→    briefs.length >= 3
242→      ? `Today's #3 problem scored ${formatScore(briefs[2].priorityScore)} &#8212; and it's a ${formatEffortLabel(briefs[2].effortEstimate).toLowerCase()} build.`
243→      : `There are ${ideaCount - 1} more problems waiting for you today.`,
244→  ];
245→  const copy = variants[dateHash % variants.length];
246→
247→  return `
248→    <table width="100%" cellpadding="0" cellspacing="0" role="presentation">
249→      <tr>
250→        <td style="padding: 0 24px;">
251→          <table width="100%" cellpadding="0" cellspacing="0" role="presentation" style="background-color: #f5f3ff; border-left: 3px solid #6366f1; border-radius: 0 8px 8px 0;">
252→            <tr>
253→              <td style="padding: 14px 20px; font-family: ${FONT_STACK}; font-size: 14px; color: #374151; line-height: 1.5;">
254→                ${copy}
255→                <a href="${escapeHtml(config.upgradeUrl)}" style="color: #6366f1; font-weight: 600; text-decoration: none;"> Unlock all problems &#8594;</a>
256→              </td>
257→            </tr>
258→          </table>
259→        </td>
260→      </tr>
261→    </table>`;
262→}
263→
264→function buildIdeaCard(
265→  brief: IdeaBrief,
266→  rank: number,
267→  locked: boolean,
268→  tier: SubscriberTier,
269→  config: Required<EmailBuilderConfig>
270→): string {
271→  const effortStyle = getEffortBadgeStyle(brief.effortEstimate);
272→  const effortLabel = formatEffortLabel(brief.effortEstimate);
273→  const ideaPath = `/idea/${brief.id || ''}`;
274→  const ideaUrl = tier === 'free'
275→    ? `${config.baseUrl}/login?next=${encodeURIComponent(ideaPath)}`
276→    : `${config.baseUrl}${ideaPath}`;
277→  const tagline = brief.tagline.length > TAGLINE_TRUNCATE_LENGTH
278→    ? brief.tagline.slice(0, TAGLINE_TRUNCATE_LENGTH) + '...'
279→    : brief.tagline;
280→
281→  if (locked) {
282→    return `
283→      <table width="100%" cellpadding="0" cellspacing="0" role="presentation" style="margin-bottom: 8px;">
284→        <tr>
285→          <td style="background-color: #f9fafb; border-radius: 8px; border: 1px solid #e5e7eb; padding: 14px 16px; font-family: ${FONT_STACK}; opacity: 0.6;">
286→            <table width="100%" cellpadding="0" cellspacing="0" role="presentation">
287→              <tr>
288→                <td width="28" style="vertical-align: top; font-size: 14px; font-weight: 700; color: #6366f1;">#${rank}</td>
289→                <td style="vertical-align: top; padding-left: 12px;">
290→                  <div style="font-size: 15px; font-weight: 600; color: #111827;">${escapeHtml(brief.name)}</div>
291→                  <div style="background-color: #d1d5db; border-radius: 4px; height: 12px; width: 70%; margin-top: 6px;"></div>
292→                </td>
293→                <td width="48" style="vertical-align: top; text-align: right;">
294→                  <span style="display: inline-block; background-color: #6366f1; color: #ffffff; padding: 2px 8px; border-radius: 4px; font-size: 11px; font-weight: 600;">PRO</span>
295→                </td>
296→              </tr>
297→            </table>
298→          </td>
299→        </tr>
300→      </table>`;
301→  }
302→
303→  return `
304→    <table width="100%" cellpadding="0" cellspacing="0" role="presentation" style="margin-bottom: 8px;">
305→      <tr>
306→        <td style="background-color: #f9fafb; border-radius: 8px; border: 1px solid #e5e7eb; padding: 14px 16px; font-family: ${FONT_STACK};">
307→          <table width="100%" cellpadding="0" cellspacing="0" role="presentation">
308→            <tr>
309→              <td width="28" style="vertical-align: top; font-size: 14px; font-weight: 700; color: #6366f1;">#${rank}</td>
310→              <td style="vertical-align: top; padding-left: 12px;">
311→                <div style="font-size: 15px; font-weight: 600; color: #111827; margin-bottom: 2px;">${escapeHtml(brief.name)}</div>
312→                <div style="font-size: 13px; color: #6b7280; margin-bottom: 6px;">${escapeHtml(tagline)}</div>
313→                <span style="display: inline-block; background-color: ${effortStyle.bg}; color: ${effortStyle.text}; padding: 2px 8px; border-radius: 4px; font-size: 11px; font-weight: 600;">${escapeHtml(effortLabel)}</span>
314→              </td>
315→              <td width="48" style="vertical-align: top; text-align: right;">
316→                <div style="font-size: 18px; font-weight: 700; color: #6366f1;">${formatScore(brief.priorityScore)}</div>
317→              </td>
318→            </tr>
319→            <tr>
320→              <td></td>
321→              <td colspan="2" style="padding-top: 8px;">
322→                <a href="${escapeHtml(ideaUrl)}" style="color: #6366f1; font-size: 14px; font-weight: 600; text-decoration: none;">View problem &#8594;</a>
323→              </td>
324→            </tr>
325→          </table>
326→        </td>
327→      </tr>
