331→function buildOtherIdeasSection(
332→  briefs: IdeaBrief[],
333→  tier: SubscriberTier,
334→  config: Required<EmailBuilderConfig>
335→): string {
336→  if (briefs.length <= 1) return '';
337→
338→  const limit = TIER_LIMITS[tier];
339→  const otherBriefs = briefs.slice(1, MAX_EMAIL_IDEAS);
340→  const lockedCount = Math.max(0, otherBriefs.length - (limit - 1));
341→  const maxLockedShown = 3;
342→  const weekendBuilds = otherBriefs
343→    .filter((b, i) => i + 2 > limit && b.effortEstimate.toLowerCase() === 'weekend')
344→    .length;
345→
346→  // Show unlocked cards + up to 3 locked cards (avoid paywall fatigue)
347→  const visibleBriefs = tier === 'free'
348→    ? otherBriefs.slice(0, (limit - 1) + maxLockedShown)
349→    : otherBriefs;
350→
351→  const rows = visibleBriefs.map((brief, index) => {
352→    const rank = index + 2;
353→    const locked = rank > limit;
354→    return buildIdeaCard(brief, rank, locked, tier, config);
355→  }).join('\n');
356→
357→  const lockedFooter = lockedCount > 0 && tier === 'free'
358→    ? `
359→      <table width="100%" cellpadding="0" cellspacing="0" role="presentation" style="margin-top: 8px;">
360→        <tr>
