341→  const maxLockedShown = 3;
342→  const weekendBuilds = otherBriefs
343→    .filter((b, i) => i + 2 > limit && b.effortEstimate.toLowerCase() === 'weekend')
344→    .length;
345→
346→  // Show unlocked cards + up to 3 locked cards (avoid paywall fatigue)
347→  const visibleBriefs = tier === 'free'
348→    ? otherBriefs.slice(0, (limit - 1) + maxLockedShown)
349→    : otherBriefs;
350→
351→  const rows = visibleBriefs.map((brief, index) => {
352→    const rank = index + 2;
353→    const locked = rank > limit;
354→    return buildIdeaCard(brief, rank, locked, tier, config);
355→  }).join('\n');
356→
357→  const lockedFooter = lockedCount > 0 && tier === 'free'
358→    ? `
359→      <table width="100%" cellpadding="0" cellspacing="0" role="presentation" style="margin-top: 8px;">
360→        <tr>
361→          <td style="text-align: center; padding: 12px 0; font-family: ${FONT_STACK};">
362→            <span style="font-size: 14px; color: #6b7280;">+${lockedCount} more problem${lockedCount > 1 ? 's' : ''} available with Pro${weekendBuilds > 0 ? ` &#8212; including ${weekendBuilds} weekend build${weekendBuilds > 1 ? 's' : ''}` : ''}</span>
363→          </td>
364→        </tr>
365→      </table>`
366→    : '';
367→
368→  return `
369→    <table width="100%" cellpadding="0" cellspacing="0" role="presentation">
370→      <tr>
371→        <td style="padding: 24px; font-family: ${FONT_STACK};">
372→          <div style="font-size: 11px; color: #9ca3af; text-transform: uppercase; letter-spacing: 0.5px; margin-bottom: 16px;">More Problems Today</div>
373→          ${rows}
374→          ${lockedFooter}
375→        </td>
376→      </tr>
377→    </table>`;
378→}
379→
380→function buildBottomCta(
381→  tier: SubscriberTier,
382→  freeCount: number,
383→  totalCount: number,
384→  config: Required<EmailBuilderConfig>
385→): string {
386→  if (tier === 'pro') return '';
387→
388→  return `
389→    <table width="100%" cellpadding="0" cellspacing="0" role="presentation" style="background-color: #111827;">
390→      <tr>
391→        <td style="padding: 32px 24px; text-align: center; font-family: ${FONT_STACK};">
392→          <div style="font-size: 20px; font-weight: 700; color: #ffffff; margin-bottom: 8px;">You browsed ${freeCount} problems today. Pro members get full specs for all of them.</div>
393→          <div style="font-size: 16px; color: rgba(255,255,255,0.7); margin-bottom: 20px;">Every problem. Every spec. Every day.</div>
394→          <table cellpadding="0" cellspacing="0" role="presentation" style="margin: 0 auto;">
395→            <tr>
396→              <td style="background-color: #ffffff; border-radius: 8px;">
397→                <a href="${escapeHtml(config.upgradeUrl)}" style="display: inline-block; padding: 14px 32px; color: #111827; font-family: ${FONT_STACK}; font-size: 16px; font-weight: 600; text-decoration: none; border-radius: 8px;">Upgrade to Pro &#8594;</a>
398→              </td>
399→            </tr>
400→          </table>
401→        </td>
402→      </tr>
403→    </table>`;
404→}
405→
406→function buildFooter(config: Required<EmailBuilderConfig>): string {
407→  return `
408→    <table width="100%" cellpadding="0" cellspacing="0" role="presentation" style="background-color: #f9fafb;">
409→      <tr>
410→        <td style="padding: 24px; text-align: center; font-family: ${FONT_STACK};">
411→          <p style="margin: 0 0 8px 0; font-size: 13px; color: #9ca3af;">You're receiving this because you signed up at zerotoship.dev.</p>
412→          <p style="margin: 0 0 8px 0; font-size: 13px;">
413→            <a href="${escapeHtml(config.baseUrl)}/settings" style="color: #6b7280; text-decoration: underline;">Manage preferences</a>
414→            &nbsp;&middot;&nbsp;
415→            <a href="${escapeHtml(config.unsubscribeUrl)}" style="color: #6b7280; text-decoration: underline;">Unsubscribe</a>
416→          </p>
417→          <p style="margin: 0; font-size: 12px; color: #9ca3af;">ZeroToShip ${new Date().getFullYear()}</p>
418→        </td>
419→      </tr>
420→    </table>`;
421→}
422→
423→export function buildDailyEmail(
424→  briefs: IdeaBrief[],
425→  tier: SubscriberTier,
426→  config: EmailBuilderConfig = {}
427→): EmailContent {
428→  const opts = { ...DEFAULT_CONFIG, ...config };
429→
430→  if (briefs.length === 0) {
431→    return {
432→      subject: 'ZeroToShip: No problems today',
433→      html: '<p>No new problems found today. Check back tomorrow!</p>',
434→      text: 'No new problems found today. Check back tomorrow!',
435→    };
436→  }
437→
438→  // Sort by priority score descending so the best idea is always #1
439→  briefs = [...briefs].sort((a, b) => Number(b.priorityScore) - Number(a.priorityScore));
440→
441→  const topIdea = briefs[0];
442→  const ideaCount = Math.min(briefs.length, MAX_EMAIL_IDEAS);
443→  const freeCount = Math.min(briefs.length, TIER_LIMITS.free);
444→  const dateStr = new Date().toLocaleDateString('en-US', {
445→    weekday: 'short',
446→    month: 'short',
447→    day: 'numeric',
448→  });
449→
450→  const subject = generateSubjectLine(topIdea, ideaCount);
451→  const previewText = generatePreviewText(topIdea, ideaCount);
452→
453→  const html = `<!DOCTYPE html>
454→<html lang="en">
455→<head>
456→  <meta charset="UTF-8">
457→  <meta name="viewport" content="width=device-width, initial-scale=1.0">
458→  <meta name="color-scheme" content="light dark">
459→  <meta name="supported-color-schemes" content="light dark">
460→  <title>${escapeHtml(subject)}</title>
461→  <!--[if mso]>
462→  <style type="text/css">
463→    table { border-collapse: collapse; }
464→    td { font-family: Arial, sans-serif; }
465→  </style>
466→  <![endif]-->
467→</head>
468→<body style="margin: 0; padding: 0; background-color: #f5f5f5; font-family: ${FONT_STACK};">
469→  ${buildPreheader(previewText)}
470→  <table width="100%" cellpadding="0" cellspacing="0" role="presentation" style="background-color: #f5f5f5;">
471→    <tr>
472→      <td align="center" style="padding: 16px 0;">
473→        <table width="600" cellpadding="0" cellspacing="0" role="presentation" style="max-width: 600px; width: 100%; background-color: #ffffff; border-radius: 8px; overflow: hidden;">
474→          <tr><td>
475→            ${buildHeader(dateStr)}
476→            ${buildStatBar(ideaCount, formatScore(topIdea.priorityScore))}
477→            ${buildHeroSection(topIdea, tier, opts)}
478→            ${tier === 'free' ? buildInlineUpgradeBanner(briefs, opts) : ''}
479→            ${buildOtherIdeasSection(briefs, tier, opts)}
480→            ${buildBottomCta(tier, freeCount, ideaCount, opts)}
481→            ${buildFooter(opts)}
482→          </td></tr>
483→        </table>
484→      </td>
485→    </tr>
486→  </table>
487→</body>
488→</html>`.trim();
489→
490→  const text = buildPlainTextEmail(briefs, tier, opts);
491→
492→  return { subject, html, text };
493→}
494→
495→function buildPlainTextEmail(
496→  briefs: IdeaBrief[],
497→  tier: SubscriberTier,
498→  config: Required<EmailBuilderConfig>
499→): string {
500→  if (briefs.length === 0) {
501→    return 'No new problems found today. Check back tomorrow!';
502→  }
503→
504→  const limit = TIER_LIMITS[tier];
505→  const topIdea = briefs[0];
506→  const ideaCount = Math.min(briefs.length, MAX_EMAIL_IDEAS);
507→  const dateStr = new Date().toLocaleDateString('en-US', {
508→    weekday: 'short',
509→    month: 'short',
510→    day: 'numeric',
511→  });
512→  const lines: string[] = [];
513→
514→  lines.push(`ZEROTOSHIP | ${dateStr}`);
515→  lines.push(`${ideaCount} problems found | 4 communities scraped | Top score: ${formatScore(topIdea.priorityScore)}`);
516→  lines.push('='.repeat(60));
517→  lines.push('');
518→
519→  lines.push("#1 TODAY'S TOP PROBLEM");
520→  lines.push('');
521→  lines.push(topIdea.name);
522→  lines.push(`"${topIdea.tagline}"`);
523→  lines.push('');
524→  lines.push(`Score: ${formatScore(topIdea.priorityScore)}/100 | Build time: ${formatEffortLabel(topIdea.effortEstimate)}`);
525→  lines.push('');
526→
527→  if (tier === 'pro') {
528→    lines.push('THE PROBLEM');
529→    lines.push(topIdea.problemStatement);
530→    lines.push('');
531→    lines.push('TARGET AUDIENCE');
532→    lines.push(topIdea.targetAudience);
533→    lines.push('');
534→    lines.push('PROPOSED SOLUTION');
535→    lines.push(topIdea.proposedSolution);
536→    lines.push('');
537→    if (topIdea.keyFeatures.length > 0) {
538→      lines.push('KEY FEATURES');
539→      topIdea.keyFeatures.slice(0, 5).forEach(f => lines.push(`  ✓ ${f}`));
540→      lines.push('');
541→    }
542→    if (topIdea.goToMarket) {
543→      lines.push('GO-TO-MARKET');
544→      lines.push(topIdea.goToMarket.launchStrategy);
545→      lines.push('');
546→    }
547→    lines.push(`View full spec on dashboard: ${config.baseUrl}/idea/${topIdea.id || ''}`);
548→  } else {
549→    lines.push(firstSentence(topIdea.problemStatement));
550→    if (topIdea.keyFeatures.length > 0) {
551→      lines.push(`The brief covers ${topIdea.keyFeatures[0].toLowerCase()}${topIdea.keyFeatures.length > 1 ? ` and ${topIdea.keyFeatures.length - 1} more technical approaches` : ''}.`);
552→    }
553→    lines.push('');
554→    lines.push(`Read the full spec: ${config.baseUrl}/idea/${topIdea.id || ''}`);
555→  }
556→  lines.push('');
557→  lines.push('-'.repeat(60));
558→  lines.push('');
559→
560→  if (briefs.length > 1) {
561→    lines.push("MORE PROBLEMS TODAY");
562→    lines.push('');
563→
564→    briefs.slice(1, MAX_EMAIL_IDEAS).forEach((brief, index) => {
565→      const rank = index + 2;
566→      const locked = rank > limit;
567→
568→      if (locked) {
569→        lines.push(`#${rank} ${brief.name} [PRO]`);
570→      } else {
571→        lines.push(`#${rank} ${brief.name} — Score: ${formatScore(brief.priorityScore)} [${formatEffortLabel(brief.effortEstimate)}]`);
572→        lines.push(`   "${brief.tagline}"`);
573→        lines.push(`   View problem: ${config.baseUrl}/idea/${brief.id || ''}`);
574→      }
575→      lines.push('');
576→    });
577→  }
578→
579→  if (tier === 'free') {
580→    const lockedCount = Math.max(0, Math.min(briefs.length, MAX_EMAIL_IDEAS) - TIER_LIMITS.free);
581→    if (lockedCount > 0) {
582→      lines.push('-'.repeat(60));
583→      lines.push(`+${lockedCount} more problems with full specs available on Pro.`);
584→      lines.push(`Unlock all problems: ${config.upgradeUrl}`);
585→      lines.push('');
586→    }
587→
588→    lines.push('-'.repeat(60));
589→    lines.push(`You browsed ${Math.min(briefs.length, TIER_LIMITS.free)} problems today. Pro members get full specs for all of them.`);
590→    lines.push('Every problem. Every spec. Every day.');
591→    lines.push(`Upgrade to Pro: ${config.upgradeUrl}`);
592→    lines.push('');
593→  }
594→
595→  lines.push('-'.repeat(60));
596→  lines.push(`Manage preferences: ${config.baseUrl}/settings`);
597→  lines.push(`Unsubscribe: ${config.unsubscribeUrl}`);
598→  lines.push(`ZeroToShip ${new Date().getFullYear()}`);
599→
600→  return lines.join('\n');
601→}
